import React from 'react'
import Vittoria from './Vittoria';
import Sconfitta from './Sconfitta';
import NuovaPartita from './NuovaPartita';

function FineGame({fineGame}){

  return (
    <>
      {fineGame === "vittoria" && <Vittoria/>}
      {fineGame === "sconfitta" && <Sconfitta/>}
      <NuovaPartita/>

    </>
  )
}

export default FineGame;
